SELECT



    sd.deleted = 0

        AND sd.student_id = #{req.studentId}


        AND s.student_no LIKE CONCAT('%', #{req.studentNo}, '%')


        AND u.real_name LIKE CONCAT('%', #{req.studentName}, '%')


        AND sd.dormitory_id = #{req.dormitoryId}


        AND d.building_id = #{req.buildingId}


        AND d.floor_number = #{req.floorNumber}


        AND sd.status = #{req.status}


        AND sd.check_in_date >= #{req.checkInDateStart}


        AND sd.check_in_date <= #{req.checkInDateEnd}


ORDER BY sd.created_at DESC

SELECT COUNT(*)
FROM student_dormitory
WHERE dormitory_id = #{dormitoryId}
AND bed_number = #{bedNumber}
AND status = 1
AND deleted = 0

    AND id != #{excludeId}
